const input = items[0].json;

const rawUrl = String(
  input.url ??
  input.body?.url ??
  input.body?.data?.url ??
  ''
).trim();

const rawQuestion = String(
  input.question ??
  input.body?.question ??
  input.body?.data?.question ??
  ''
).trim();

if (!rawUrl) {
  throw new Error('Missing required field: url');
}

if (!rawQuestion) {
  throw new Error('Missing required field: question');
}

let normalizedUrl = rawUrl;

if (normalizedUrl.startsWith('//')) {
  normalizedUrl = `https:${normalizedUrl}`;
} else if (!/^https?:\/\//i.test(normalizedUrl)) {
  normalizedUrl = `https://${normalizedUrl}`;
}

const match = normalizedUrl.match(/^https?:\/\/([^\/?#]+)(\/[^?#]*)?/i);

if (!match) {
  throw new Error(`Invalid URL provided: ${rawUrl}`);
}

const domain = match[1];
const pathname = match[2] || '';

const handleMatch = pathname.match(/\/products\/([^/?#]+)/i);

if (!handleMatch) {
  throw new Error('Could not extract Shopify product handle from the URL');
}

const handle = decodeURIComponent(handleMatch[1]);

return [
  {
    json: {
      url: normalizedUrl,
      question: rawQuestion,
      handle,
      domain,
    },
  },
];

// Extract Page Signals
// Replace "Fetch Page HTML" with the exact name of your HTTP node
// that returns the page HTML in a field called `data`.

const input = $('Validate + Normalize Input').first().json || {};
const pageNode = $('Fetch Page HTML').first().json || {};

const html = String(pageNode.data || '');
const url = input.url || null;
const question = input.question || null;
const handle = input.handle || null;
const domain = input.domain || null;

function decodeEntities(str) {
  if (!str) return '';
  return String(str)
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function firstMatch(re, text = html) {
  const m = text.match(re);
  return m?.[1] ? decodeEntities(m[1]) : null;
}

function stripHtml(input) {
  return decodeEntities(
    String(input)
      .replace(/<script[\s\S]*?<\/script>/gi, ' ')
      .replace(/<style[\s\S]*?<\/style>/gi, ' ')
      .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
      .replace(/<template[\s\S]*?<\/template>/gi, ' ')
      .replace(/<iframe[\s\S]*?<\/iframe>/gi, ' ')
      .replace(/<svg[\s\S]*?<\/svg>/gi, ' ')
      .replace(/<[^>]+>/g, ' ')
  );
}

function extractJsonLdBlocks(text) {
  const blocks = [];
  const re = /<script[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;

  for (const m of text.matchAll(re)) {
    const raw = m[1]?.trim();
    if (!raw) continue;
    try {
      blocks.push(JSON.parse(raw));
    } catch {
      // ignore invalid JSON-LD
    }
  }

  return blocks;
}

function flattenJsonLd(blocks) {
  const flat = [];
  for (const block of blocks || []) {
    if (Array.isArray(block)) flat.push(...block);
    else if (block && typeof block === 'object') flat.push(block);
  }
  return flat;
}

function walkJsonLd(node, visit, seen = new Set()) {
  if (!node || typeof node !== 'object') return;
  if (seen.has(node)) return;
  seen.add(node);

  visit(node);

  if (Array.isArray(node)) {
    for (const item of node) walkJsonLd(item, visit, seen);
    return;
  }

  for (const value of Object.values(node)) {
    if (value && typeof value === 'object') {
      walkJsonLd(value, visit, seen);
    }
  }
}

function coerceNumber(value) {
  if (value === null || value === undefined) return null;
  const n = Number(String(value).replace(/,/g, '').trim());
  return Number.isFinite(n) ? n : null;
}

function extractReviewSignals(htmlText, flatJsonLd) {
  const reviewBlocks = [];
  const aggregateRatings = [];

  walkJsonLd(flatJsonLd, (node) => {
    const type = node['@type'];
    const types = Array.isArray(type) ? type : [type];

    if (types.includes('Product') || types.includes('AggregateOffer') || types.includes('Review')) {
      if (node.aggregateRating) aggregateRatings.push(node.aggregateRating);
      if (node.review) reviewBlocks.push(node.review);
      if (Array.isArray(node.reviews)) reviewBlocks.push(...node.reviews);
    }

    if (node.aggregateRating && !aggregateRatings.includes(node.aggregateRating)) {
      aggregateRatings.push(node.aggregateRating);
    }
    if (node.review && !reviewBlocks.includes(node.review)) {
      reviewBlocks.push(node.review);
    }
    if (Array.isArray(node.reviews)) {
      for (const r of node.reviews) reviewBlocks.push(r);
    }
  });

  const firstAgg = aggregateRatings.find(Boolean) || null;
  const firstReview = reviewBlocks.find(Boolean) || null;

  const ratingValue =
    coerceNumber(firstAgg?.ratingValue) ??
    coerceNumber(firstReview?.reviewRating?.ratingValue) ??
    coerceNumber(firstMatch(/itemprop=["']ratingValue["'][^>]*content=["']([^"']+)["']/i, htmlText)) ??
    coerceNumber(firstMatch(/rated\s+([0-9.]+)\s+out of\s+5/i, stripHtml(htmlText))) ??
    null;

  const reviewCount =
    coerceNumber(firstAgg?.reviewCount) ??
    coerceNumber(firstAgg?.ratingCount) ??
    coerceNumber(firstMatch(/itemprop=["']reviewCount["'][^>]*content=["']([^"']+)["']/i, htmlText)) ??
    coerceNumber(firstMatch(/([\d,]+)\s+reviews?\b/i, stripHtml(htmlText))) ??
    null;

  const bestRating =
    coerceNumber(firstAgg?.bestRating) ??
    coerceNumber(firstReview?.reviewRating?.bestRating) ??
    null;

  const worstRating =
    coerceNumber(firstAgg?.worstRating) ??
    coerceNumber(firstReview?.reviewRating?.worstRating) ??
    null;

  const ratingTextMatches = [...htmlText.matchAll(/rated\s+([0-9.]+)\s+out of\s+5/gi)];
  const reviewTextMatches = [...htmlText.matchAll(/([\d,]+)\s+reviews?\b/gi)];
  const reviewSectionMentions = [...htmlText.matchAll(/\breviews?\b/gi)].length;

  const hasReviews =
    reviewCount !== null ||
    ratingValue !== null ||
    reviewBlocks.length > 0 ||
    reviewSectionMentions > 0 ||
    ratingTextMatches.length > 0;

  return {
    hasReviews,
    reviewCount,
    ratingValue,
    bestRating,
    worstRating,
    jsonLdReviewBlockCount: reviewBlocks.length,
    jsonLdAggregateRatingCount: aggregateRatings.length,
    reviewTextMentions: reviewSectionMentions,
    reviewMentionSamples: reviewTextMatches.slice(0, 5).map((m) => m[0]),
    ratingMentionSamples: ratingTextMatches.slice(0, 5).map((m) => m[0]),
    reviewSource: reviewBlocks.length > 0 || aggregateRatings.length > 0 ? 'jsonld' : 'html',
    rawReviewBlocks: reviewBlocks.slice(0, 5),
    rawAggregateRatings: aggregateRatings.slice(0, 5),
  };
}

function extractImageUrls(text) {
  const urls = [];

  // Absolute image URLs
  const abs = text.match(/https?:\/\/[^"'`\s>]+?\.(?:png|jpe?g|webp|avif)(?:\?[^"'`\s>]*)?/gi) || [];
  urls.push(...abs);

  // Next.js image URLs
  const nextImageMatches = [...text.matchAll(/\/_next\/image\?url=([^"'`\s>]+?)(?:&[^"'`\s>]*)?/gi)];
  for (const m of nextImageMatches) {
    try {
      const decoded = decodeURIComponent(m[1]);
      if (decoded.startsWith('http')) {
        urls.push(decoded);
      } else if (domain) {
        urls.push(`https://${domain}${decoded.startsWith('/') ? '' : '/'}${decoded}`);
      }
    } catch {
      // ignore
    }
  }

  return [...new Set(urls)];
}

function getMainSection(text) {
  const main = text.match(/<main\b[^>]*>([\s\S]*?)<\/main>/i);
  if (main?.[1]) return main[1];

  const article = text.match(/<article\b[^>]*>([\s\S]*?)<\/article>/i);
  if (article?.[1]) return article[1];

  const body = text.match(/<body\b[^>]*>([\s\S]*?)<\/body>/i);
  if (body?.[1]) return body[1];

  return text;
}

function extractContentSections(text) {
  const source = getMainSection(text);
  const sections = [];

  const patterns = [
    { tag: 'p', re: /<p\b[^>]*>([\s\S]*?)<\/p>/gi },
    { tag: 'li', re: /<li\b[^>]*>([\s\S]*?)<\/li>/gi },
    { tag: 'h', re: /<h[1-6]\b[^>]*>([\s\S]*?)<\/h[1-6]>/gi },
    { tag: 'blockquote', re: /<blockquote\b[^>]*>([\s\S]*?)<\/blockquote>/gi },
    { tag: 'figcaption', re: /<figcaption\b[^>]*>([\s\S]*?)<\/figcaption>/gi },
    { tag: 'td', re: /<td\b[^>]*>([\s\S]*?)<\/td>/gi },
    { tag: 'div', re: /<div\b[^>]*>([\s\S]*?)<\/div>/gi },
    { tag: 'span', re: /<span\b[^>]*>([\s\S]*?)<\/span>/gi },
  ];

  for (const { tag, re } of patterns) {
    for (const m of source.matchAll(re)) {
      const text = stripHtml(m[1]);
      if (!text) continue;

      sections.push({
        tag,
        index: m.index ?? null,
        text,
        wordCount: text.split(/\s+/).filter(Boolean).length,
      });
    }
  }

  // Preserve page order
  sections.sort((a, b) => (a.index ?? 0) - (b.index ?? 0));

  // Exact dedupe only; do not semantically filter anything out
  const seen = new Set();
  const deduped = [];
  for (const s of sections) {
    const key = `${s.tag}::${s.text.toLowerCase()}`;
    if (seen.has(key)) continue;
    seen.add(key);
    deduped.push(s);
  }

  return deduped;
}

function groupSectionsByTag(sections) {
  const grouped = {};
  for (const s of sections || []) {
    if (!grouped[s.tag]) grouped[s.tag] = [];
    grouped[s.tag].push(s.text);
  }
  return grouped;
}

const title =
  firstMatch(/<meta[^>]+property=["']og:title["'][^>]+content=["']([^"']+)["']/i) ||
  firstMatch(/<meta[^>]+name=["']twitter:title["'][^>]+content=["']([^"']+)["']/i) ||
  firstMatch(/<title>([\s\S]*?)<\/title>/i);

const description =
  firstMatch(/<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)["']/i) ||
  firstMatch(/<meta[^>]+property=["']og:description["'][^>]+content=["']([^"']+)["']/i) ||
  firstMatch(/<meta[^>]+name=["']twitter:description["'][^>]+content=["']([^"']+)["']/i);

const canonical =
  firstMatch(/<link[^>]+rel=["']canonical["'][^>]+href=["']([^"']+)["']/i) ||
  firstMatch(/<meta[^>]+property=["']og:url["'][^>]+content=["']([^"']+)["']/i);

const ogImage =
  firstMatch(/<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i) ||
  firstMatch(/<meta[^>]+name=["']twitter:image["'][^>]+content=["']([^"']+)["']/i);

const jsonLdBlocks = extractJsonLdBlocks(html);
const flatJsonLd = flattenJsonLd(jsonLdBlocks);
const imageUrls = extractImageUrls(html);
const contentSections = extractContentSections(html);
const sectionsByTag = groupSectionsByTag(contentSections);
const fullText = stripHtml(html);
const reviews = extractReviewSignals(html, flatJsonLd);

return [
  {
    json: {
      url,
      question,
      handle,
      domain,
      extracted: {
        title,
        description,
        canonical,
        ogImage,
        imageUrls,
        reviews,
        jsonLdBlocks,
        jsonLdTypes: [...new Set(flatJsonLd.map((x) => x?.['@type']).filter(Boolean))],
        contentSections,
        sectionsByTag,
        fullText,
        textSample: fullText.slice(0, 12000),
      },
      meta: {
        htmlLength: html.length,
        textLength: fullText.length,
        jsonLdCount: jsonLdBlocks.length,
        imageCount: imageUrls.length,
        sectionCount: contentSections.length,
        reviewDetected: reviews.hasReviews,
        reviewCountDetected: reviews.reviewCount,
        ratingValueDetected: reviews.ratingValue,
      },
    },
  },
];

const input = items[0].json || {};

function failure(stage, message) {
  return [
    {
      json: {
        success: false,
        answer: null,
        confidence: 'low',
        evidence: [],
        missing_data: [message],
        improvement_suggestions: [
          'Check the upstream LLM node output format.',
          'Retry the request after verifying the extracted data.',
        ],
        question_type: 'other',
        can_answer_directly: false,
        error: {
          stage,
          message,
        },
      },
    },
  ];
}

// If the LLM node itself already errored
if (input.error) {
  return failure(
    'llm_engine',
    input.error.message || 'LLM node failed'
  );
}

let result;

try {
  result = input.output?.[0]?.content?.[0]?.text;
} catch {
  return failure(
    'llm_extract',
    'Could not extract OpenAI response content'
  );
}

if (!result) {
  return failure(
    'llm_extract',
    'OpenAI response content was empty'
  );
}

if (typeof result === 'string') {
  try {
    result = JSON.parse(result);
  } catch {
    return failure(
      'llm_parse',
      'OpenAI output was not valid JSON'
    );
  }
}

if (!result || typeof result !== 'object') {
  return failure(
    'llm_parse',
    'OpenAI output was invalid or empty'
  );
}

return [
  {
    json: {
      success: Boolean(result.success ?? true),
      answer: result.answer ?? null,
      confidence: ['high', 'medium', 'low'].includes(result.confidence)
        ? result.confidence
        : 'low',
      evidence: Array.isArray(result.evidence) ? result.evidence : [],
      missing_data: Array.isArray(result.missing_data) ? result.missing_data : [],
      improvement_suggestions: Array.isArray(result.improvement_suggestions)
        ? result.improvement_suggestions
        : [],
      question_type: result.question_type ?? 'other',
      can_answer_directly: Boolean(result.can_answer_directly),
      error: result.error ?? null,
    },
  },
];

