const input = $('Validate + Normalize Input').first().json || {};
const fetchNode = $('Fetch Page HTML').first().json || {};

const errorMessage =
  fetchNode.error?.message ||
  fetchNode.message ||
  fetchNode.body?.message ||
  'Failed to fetch page HTML';

return [
  {
    json: {
      success: false,
      answer: null,
      confidence: 'low',
      evidence: [],
      missing_data: [
        `Could not fetch the product page HTML. ${errorMessage}`,
      ],
      improvement_suggestions: [
        'Verify the product URL is correct and publicly accessible.',
        'Check whether the page is blocking automated requests.',
        'Retry the workflow after the page is available again.',
      ],
      question_type: 'other',
      can_answer_directly: false,
      error: {
        stage: 'fetch_page_html',
        message: errorMessage,
      },
      url: input.url || null,
      question: input.question || null,
      handle: input.handle || null,
      domain: input.domain || null,
    },
  },
];

const input = items[0].json || {};

const errorMessage =
  input.error?.message ||
  input.message ||
  input.body?.message ||
  'LLM processing failed';

return [
  {
    json: {
      success: false,
      answer: null,
      confidence: 'low',
      evidence: [],
      missing_data: [
        `The AI evaluation step failed. ${errorMessage}`,
      ],
      improvement_suggestions: [
        'Retry the request.',
        'Verify the extracted product data is valid.',
        'Check whether the model returned malformed output.',
      ],
      question_type: 'other',
      can_answer_directly: false,
      error: {
        stage: 'llm_engine',
        message: errorMessage,
      },
    },
  },
];
